INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('heelevel3-d0d1b9a2-moex-00215', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-112-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X1年初與員工約定，若員工繼續服務至X4年底，則可在X4年底選擇相當10,000股之現 金或15,000股之普通股。甲公司於考量相關條件後，X1年初選擇現金方案之每股公允價值為$20， 且X1年初選擇股份方案之每股公允價值為$15。若X1年底選擇現金方案之每股公允價值為$25， 選擇股份方案之每股公允價值為$20，則此約定對甲公司X1年度薪資費用有何影響？', '["增加$56,250", "增加$68,750", "增加$106,250", "增加$137,500"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:59+00:00", "source_pdf_sha1": "2b5ab581203c", "answer_pdf_sha1": "5685b74c595b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00216', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-112-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X1年1月1日以$950,000購買乙公司所發行之債券，並分類為透過其他綜合損益按公 允價值衡量，原始有效利率為11%。X1年底甲公司認列利息收入$104,500及債券投資折價攤 銷$4,500，是日該債券投資公允價值為$940,000。乙公司於X2年底依約定支付現金利息 $100,000，但因已經發生財務困難，致債券公允價值僅為$380,000。請問甲公司應於X2年底之 分錄認列多少債券投資評價調整？', '["$574,500", "$574,995", "$564,500", "$564,995"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:59+00:00", "source_pdf_sha1": "2b5ab581203c", "answer_pdf_sha1": "5685b74c595b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00217', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-112-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '甲公司在X1年1月1日以$5,320,000買入乙公司發行的面額$6,000,000，無息，4年期公司債，交 易成本為$10,920，分類為透過其他綜合損益按公允價值衡量。購買當日12個月的預期信用損 失預估為$40,000，原始的有效利率為3%。X1年12月31日該債券的信用風險已經顯著增加， 當日12個月的預期信用損失預估為$64,750，而當日存續期間的預期信用損失預估為$391,000。 若甲公司自購買日就將該債券歸類為按攤銷後成本衡量之債券投資，則二種分類下，X1年淨 利的差異為何？', '["$0", "$10,920", "$40,000", "$64,720"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:59+00:00", "source_pdf_sha1": "2b5ab581203c", "answer_pdf_sha1": "5685b74c595b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00218', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-112-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X1年1月1日為購買一項科技專利，同時發生下列現金支出項目，若該專利之法律及經 濟耐用年限分別為10年及5年，則甲公司X1年1月1日應認列為「無形資產－專利權」之金額為何？ ⑴繳交專利權過戶註冊規費$10,000 ⑵訓練員工操作專利$20,000 ⑶購買供專利使用的原料$30,000 ⑷為使該專利達預計營運狀態而直接產生之員工福利$40,000 ⑸管理、規劃如何使用該專利權所發生之管理費$50,000 ⑹支給原專利權人$60,000', '["$110,000", "$130,000", "$150,000", "$170,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:59+00:00", "source_pdf_sha1": "2b5ab581203c", "answer_pdf_sha1": "5685b74c595b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00219', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-112-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '若甲公司X1年12月31日試算表上有下列項目及金額，則依IAS38「無形資產」之規定，應包 括在資產負債表可辨認無形資產之最高金額為何？ 長期應收款 $10,000 預付6個月之租金 20,000 發展商標之成本 30,000 購買商標之成本 40,000 發展專利權之成本 50,000 購買生產存貨之專利權成本 60,000 內部發展之商譽 70,000 購買整個公司時之商譽 80,000 研究階段支出 90,000 每年支付的特許權年費 100,000', '["$180,000", "$200,000", "$220,000", "$240,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:59+00:00", "source_pdf_sha1": "2b5ab581203c", "answer_pdf_sha1": "5685b74c595b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00220', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-112-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X1年1月1日以$420,000，外加手續費$10,000，購入乙公司普通股股票，並選擇將該 股票後續公允價值的變動，列報於其他綜合損益中。若該股票於X1年12月31日的公允價值為 $440,000，且甲公司於X2年2月初賣出全部股票，扣除手續費$20,000後，獲得現金$430,000， 則有關此權益投資對甲公司之影響，下列敘述何者正確？', '["X1年之本期淨利減少$10,000", "X2年之本期淨利減少$30,000", "X1年之本期綜合損益增加權益$10,000", "X2年之本期綜合損益減少權益$30,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:59+00:00", "source_pdf_sha1": "2b5ab581203c", "answer_pdf_sha1": "5685b74c595b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00221', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-112-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '甲公司X1年度流動資產僅有現金及約當現金、應收帳款、存貨及預付貨款4項，合計數為 $600,000，其中現金及約當現金共$140,000、預付貨款$100,000，流動比率4，速動比率2，存 貨週轉率為4次。若甲公司X1年期初存貨等於期末存貨，則X1年度之銷貨成本為若干？', '["條件不足，無法計算", "$1,200,000", "$800,000", "$400,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:59+00:00", "source_pdf_sha1": "2b5ab581203c", "answer_pdf_sha1": "5685b74c595b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00222', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-112-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '當公司採用傳統零售價法進行存貨估計時，下列有幾項會影響其成本比率（成本對零售價比', '["進貨退出", "淨加價", "淨減價", "期初存貨  ⑤非常損耗  ⑥正常損耗 ⑦員工折扣"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:59+00:00", "source_pdf_sha1": "2b5ab581203c", "answer_pdf_sha1": "5685b74c595b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00223', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-112-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '甲公司111年度稅前淨利$1,000,000，其他相關資料如下： 建築物折舊費用 $200,000 專利權攤銷 50,000 出售設備得款（含資產處分利益$10,000） 180,000 預期信用減損損失 15,000 應收帳款增加數 10,000 存貨增加數 20,000 預收收入減少數 30,000 應付帳款增加數 40,000 支付所得稅 70,000 甲公司採間接法編製現金流量表，試問甲公司111年度來自營業活動之現金流量為多少？', '["營業活動之淨現金流量流入$1,205,000", "營業活動之淨現金流量流入$1,225,000", "營業活動之淨現金流量流入$1,165,000", "營業活動之淨現金流量流入$1,245,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:59+00:00", "source_pdf_sha1": "2b5ab581203c", "answer_pdf_sha1": "5685b74c595b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00224', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-112-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '甲公司在112年5月1日將其專利權與乙公司的金融資產投資進行交換，甲公司交換後持有該金 融資產投資的意圖為交易目的，已知對甲公司而言，換入的金融資產投資與換出的專利權之 未來現金流量型態不同，兩項資產於112年5月1日之相關資訊如下，兩項資產公允價值不等之 價差以現金補足，試問下列敘述何者正確？ 專利權 金融資產 原始購入成本 $1,800,000 111年12月31日 $1,300,000 之帳面金額 112年5月1日帳 1,000,000 112年5月1日之 1,500,000 上累計攤銷額 公允價值 112年5月1日之 1,200,000 公允價值', '["甲公司借記透過其他綜合損益按公允價值衡量之金融資產$1,500,000", "甲公司借記透過損益按公允價值衡量之金融資產$1,200,000", "甲公司貸記資產交換利益$200,000", "甲公司貸記資產交換利益$400,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:59+00:00", "source_pdf_sha1": "2b5ab581203c", "answer_pdf_sha1": "5685b74c595b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL)
